import React, { useEffect, useState } from 'react';
import { View, Text, Button, TextInput, Alert } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import ReactNativeBiometrics from 'react-native-biometrics';

const rnBiometrics = new ReactNativeBiometrics();

const App = () => {
  const [authenticated, setAuthenticated] = useState(false);
  const [password, setPassword] = useState('');
  const [inputPassword, setInputPassword] = useState('');

  useEffect(() => {
    checkAuthentication();
  }, []);

  const checkAuthentication = async () => {
    const authFlag = await AsyncStorage.getItem('authenticated');
    if (authFlag === 'true') {
      setAuthenticated(true);
    } else {
      promptBiometric();
    }
  };

  const promptBiometric = () => {
    rnBiometrics.simplePrompt({ promptMessage: 'Authenticate' })
      .then(resultObject => {
        const { success } = resultObject;
        if (success) {
          authenticateUser();
        } else {
          console.log('User cancelled biometric prompt');
        }
      })
      .catch(() => {
        console.log('Biometrics failed');
      });
  };

  const authenticateUser = async () => {
    await AsyncStorage.setItem('authenticated', 'true');
    setAuthenticated(true);
  };

  const handlePasswordLogin = async () => {
    if (inputPassword === password) {
      await authenticateUser();
    } else {
      Alert.alert('Incorrect password');
    }
  };

  if (authenticated) {
    return <View><Text>You are authenticated!</Text></View>;
  }

  return (
    <View>
      <Text>Login Screen</Text>
      <TextInput
        placeholder="Enter Password"
        secureTextEntry
        value={inputPassword}
        onChangeText={setInputPassword}
      />
      <Button title="Login with Password" onPress={handlePasswordLogin} />
    </View>
  );
};

export default App;